import { create } from 'zustand';
import { Cell, generateBoard } from '../utils/gameUtils';
import { supabase } from '../lib/supabase';

export interface LeaderboardEntry {
  id?: number;
  nickname: string;
  score: number; // clicks
  created_at?: string;
}

export interface GameMove {
  row: number;
  col: number;
  result: 'empty' | 'body' | 'head';
  time: number;
}

export interface GameRecord {
  id: string;
  timestamp: number;
  mode: 'classic' | 'custom';
  clicks: number;
  isWin: boolean;
  totalHeads: number;
  foundHeads: number;
  moves: GameMove[];
}

interface GameState {
  board: Cell[][];
  totalHeads: number;
  foundHeads: number;
  clicks: number;
  isGameOver: boolean;
  isWin: boolean;
  moves: GameMove[];
  history: GameRecord[];

  nickname: string;
  setNickname: (name: string) => void;
  gameMode: 'classic' | 'custom';
  setGameMode: (mode: 'classic' | 'custom') => void;
  leaderboard: LeaderboardEntry[];
  fetchLeaderboard: () => Promise<void>;
  addToLeaderboard: (score: number) => Promise<void>;

  planeCounts: number[];
  setPlaneCounts: (counts: number[]) => void;

  initGame: () => void;
  revealCell: (row: number, col: number) => void;
  toggleMark: (row: number, col: number) => void;
  
  logout: () => void;
  revealAll: () => void;
  saveGameRecord: () => void;
  loadHistory: () => void;
}

export const useGameStore = create<GameState>((set, get) => ({
  board: [],
  totalHeads: 0,
  foundHeads: 0,
  clicks: 0,
  isGameOver: false,
  isWin: false,
  moves: [],
  history: [],
  
  nickname: localStorage.getItem('nickname') || '',
  setNickname: (name) => {
    localStorage.setItem('nickname', name);
    set({ nickname: name });
    get().loadHistory();
  },
  
  loadHistory: () => {
    const { nickname } = get();
    if (!nickname) {
        set({ history: [] });
        return;
    }
    const storedHistory = localStorage.getItem(`history_${nickname}`);
    if (storedHistory) {
        set({ history: JSON.parse(storedHistory) });
    } else {
        set({ history: [] });
    }
  },
  
  gameMode: 'classic',
  setGameMode: (mode) => {
    if (mode === 'classic') {
      set({ gameMode: mode, planeCounts: [1, 1, 1] });
    } else {
      set({ gameMode: mode });
    }
    // Restart game when mode changes
    setTimeout(() => get().initGame(), 0);
  },

  leaderboard: [],
  
  fetchLeaderboard: async () => {
    const { data, error } = await supabase
      .from('leaderboard')
      .select('*')
      .order('score', { ascending: true }); // Get all to filter in JS for now, or use complex SQL
      
    if (error) {
      console.error('Error fetching leaderboard:', error);
      return;
    }
    
    if (data) {
      // Group by nickname and take the min score
      const highestScores = data.reduce((acc: any, curr) => {
        if (!acc[curr.nickname] || curr.score < acc[curr.nickname].score) {
          acc[curr.nickname] = curr;
        }
        return acc;
      }, {});

      const uniqueLeaderboard = Object.values(highestScores)
        .sort((a: any, b: any) => a.score - b.score)
        .slice(0, 20);

      set({ leaderboard: uniqueLeaderboard as LeaderboardEntry[] });
    }
  },

  addToLeaderboard: async (score) => {
    const { nickname } = get();
    if (!nickname) return;
    
    // Insert into Supabase
    const { error } = await supabase
      .from('leaderboard')
      .insert([{ nickname, score }]);
      
    if (error) {
      console.error('Error adding to leaderboard:', error);
    } else {
      // Refresh leaderboard after adding
      get().fetchLeaderboard();
    }
  },

  planeCounts: [1, 1, 1],
  setPlaneCounts: (counts) => set({ planeCounts: counts }),

  initGame: () => {
    const { planeCounts } = get();
    const { board, totalHeads } = generateBoard(planeCounts);
    set({
      board,
      totalHeads,
      foundHeads: 0,
      clicks: 0,
      isGameOver: false,
      isWin: false,
      moves: [],
    });
  },

  logout: () => {
    localStorage.removeItem('nickname');
    set({
      nickname: '',
      board: [],
      totalHeads: 0,
      foundHeads: 0,
      clicks: 0,
      isGameOver: false,
      isWin: false,
      moves: [],
      history: [],
      leaderboard: [],
    });
  },

  revealAll: () => {
    const { board } = get();
    const newBoard = board.map(row => row.map(cell => ({ ...cell, revealed: true })));
    set({ board: newBoard });
  },

  saveGameRecord: () => {
    const { nickname, gameMode, clicks, isWin, moves, totalHeads, foundHeads } = get();
    const record: GameRecord = {
      id: crypto.randomUUID(),
      timestamp: Date.now(),
      mode: gameMode,
      clicks,
      isWin,
      totalHeads,
      foundHeads,
      moves,
    };

    const storedHistory = localStorage.getItem(`history_${nickname}`);
    const history: GameRecord[] = storedHistory ? JSON.parse(storedHistory) : [];
    history.unshift(record);
    localStorage.setItem(`history_${nickname}`, JSON.stringify(history));
    set({ history });
  },

  revealCell: (row: number, col: number) => {
    const { board, isGameOver, foundHeads, totalHeads, clicks, gameMode, addToLeaderboard, moves } = get();

    if (isGameOver) return;
    if (board[row][col].revealed) return;

    // Create a new board copy to maintain immutability
    const newBoard = board.map((r) => r.map((c) => ({ ...c })));
    const cell = newBoard[row][col];
    cell.revealed = true;

    let newFoundHeads = foundHeads;
    let newIsGameOver = isGameOver;
    let newIsWin = false;

    if (cell.type === 'head') {
      newFoundHeads++;
      if (newFoundHeads === totalHeads) {
        newIsGameOver = true;
        newIsWin = true;
      }
    }

    const newClicks = clicks + 1;
    const newMoves = [...moves, { row, col, result: cell.type, time: Date.now() }];

    set({
      board: newBoard,
      clicks: newClicks,
      foundHeads: newFoundHeads,
      isGameOver: newIsGameOver,
      isWin: newIsWin,
      moves: newMoves,
    });

    if (newIsGameOver) {
      get().saveGameRecord();
      // Delay reveal all for effect
      setTimeout(() => {
          get().revealAll();
      }, 500);
      
      // If game won and classic mode, add to leaderboard
      if (newIsWin && gameMode === 'classic') {
        addToLeaderboard(newClicks);
      }
    }
  },

  toggleMark: (row: number, col: number) => {
    const { board, isGameOver } = get();

    if (isGameOver) return;
    if (board[row][col].revealed) return;

    const newBoard = board.map((r) => r.map((c) => ({ ...c })));
    newBoard[row][col].marked = !newBoard[row][col].marked;

    set({ board: newBoard });
  },
}));