import React, { useEffect, useState } from 'react';
import Board from './Board';
import Controls from './Controls';
import RulesModal from './RulesModal';
import NicknameInput from './NicknameInput';
import Leaderboard from './Leaderboard';
import { useGameStore } from '../store/useGameStore';
import { LogOut, History, MessageSquare } from 'lucide-react';
import GameHistory from './GameHistory';
import DanmuOverlay from './DanmuOverlay';

const Game: React.FC = () => {
  const { initGame, nickname, logout, gameMode } = useGameStore();
  const [isRulesOpen, setIsRulesOpen] = useState(false);
  const [isLeaderboardOpen, setIsLeaderboardOpen] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [showDanmu, setShowDanmu] = useState(true);

  // Initialize game on mount
  useEffect(() => {
    initGame();
    // Auto open rules on first load
    setIsRulesOpen(true);
  }, [initGame]);

  if (!nickname) {
    return <NicknameInput />;
  }

  return (
    <div className="flex flex-col items-center w-full max-w-4xl gap-6 animate-in fade-in duration-500 relative">
      <div className="flex flex-col items-center relative w-full">
        <h1 className="text-3xl font-bold text-gray-800 mb-1">寻机头小游戏 <span className="text-sm font-normal text-blue-600 bg-blue-50 px-2 py-0.5 rounded-full align-middle">v3.0</span></h1>
        
        <div className="flex items-center gap-4 mt-2">
            <p className="text-sm text-gray-500">欢迎你，<span className="font-bold text-gray-700">{nickname}</span></p>
            <div className="flex gap-2">
                <button 
                    onClick={() => setIsHistoryOpen(true)}
                    className="p-1.5 text-xs bg-gray-100 hover:bg-gray-200 text-gray-700 rounded flex items-center gap-1 transition-colors"
                    title="游戏记录"
                >
                    <History size={14} />
                    记录
                </button>
                <button 
                    onClick={logout}
                    className="p-1.5 text-xs bg-red-50 hover:bg-red-100 text-red-600 rounded flex items-center gap-1 transition-colors"
                    title="退出登录"
                >
                    <LogOut size={14} />
                    退出
                </button>
            </div>
        </div>

        {gameMode === 'classic' && (
            <div className="absolute top-0 right-0">
                <button
                    onClick={() => setShowDanmu(!showDanmu)}
                    className={`p-2 rounded-full ${showDanmu ? 'text-blue-500 bg-blue-50' : 'text-gray-400 bg-gray-100'}`}
                    title={showDanmu ? "关闭弹幕" : "开启弹幕"}
                >
                    <MessageSquare size={20} />
                </button>
            </div>
        )}
      </div>
      
      <div className="w-full flex flex-col items-center gap-6 relative">
        <Controls 
          onOpenRules={() => setIsRulesOpen(true)} 
          onOpenLeaderboard={() => setIsLeaderboardOpen(true)}
        />
        <div className="relative w-full">
            <Board />
            {gameMode === 'classic' && showDanmu && <DanmuOverlay />}
        </div>
      </div>

      {/* Spacer for bottom input to avoid overlapping content */}
      {gameMode === 'classic' && showDanmu && <div className="h-16 w-full shrink-0" />}

      <RulesModal isOpen={isRulesOpen} onClose={() => setIsRulesOpen(false)} />
      
      {isLeaderboardOpen && (
        <Leaderboard onClose={() => setIsLeaderboardOpen(false)} />
      )}

      {isHistoryOpen && (
        <GameHistory onClose={() => setIsHistoryOpen(false)} />
      )}
      
      <div className="text-sm text-gray-400 mt-8">
        Designed by Trae | v3.0
      </div>
    </div>
  );
};

export default Game;