import React from 'react';
import { PLANE_SHAPES } from '../utils/constants';
import { X } from 'lucide-react';

interface RulesModalProps {
  isOpen: boolean;
  onClose: () => void;
}

const RulesModal: React.FC<RulesModalProps> = ({ isOpen, onClose }) => {
  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50 p-4">
      <div className="bg-white rounded-lg shadow-xl w-full max-w-lg max-h-[90vh] overflow-y-auto">
        <div className="flex justify-between items-center p-4 border-b">
          <h2 className="text-xl font-bold">游戏规则</h2>
          <button onClick={onClose} className="text-gray-500 hover:text-gray-700">
            <X size={24} />
          </button>
        </div>
        
        <div className="p-4 space-y-4">
          <p>在16x16的网格中寻找隐藏的飞机机头。</p>
          <ul className="list-disc pl-5 space-y-1">
            <li>点击格子进行探测。</li>
            <li><span className="text-gray-500 font-bold">灰色</span>：空地</li>
            <li><span className="text-blue-500 font-bold">蓝色</span>：机身</li>
            <li><span className="text-red-500 font-bold">红色</span>：机头 (目标)</li>
            <li>找到所有红色机头即可获胜！</li>
          </ul>

          <h3 className="font-bold text-lg mt-4">飞机形状示意图</h3>
          <p className="text-sm text-gray-600 mb-2">飞机可能被旋转 (上, 下, 左, 右)</p>
          
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
            {PLANE_SHAPES.map((shape, idx) => (
              <div key={idx} className="border p-2 rounded flex flex-col items-center">
                <span className="mb-2 font-medium">飞机 {idx + 1}</span>
                <div className="grid grid-cols-5 gap-1 bg-gray-100 p-1">
                  {shape.map((row, r) =>
                    row.map((val, c) => (
                      <div
                        key={`${r}-${c}`}
                        className={`w-4 h-4 ${
                          val === 0 ? 'bg-transparent' :
                          val === 1 ? 'bg-blue-500' : 'bg-red-500'
                        }`}
                      />
                    ))
                  )}
                </div>
              </div>
            ))}
          </div>
        </div>
        
        <div className="p-4 border-t flex justify-end">
          <button
            onClick={onClose}
            className="bg-blue-600 text-white py-2 px-4 rounded hover:bg-blue-700"
          >
            开始游戏
          </button>
        </div>
      </div>
    </div>
  );
};

export default RulesModal;
