import React, { useState } from 'react';
import { X, Play, Calendar, Trophy, Skull } from 'lucide-react';
import { useGameStore, GameRecord, GameMove } from '../store/useGameStore';
import { GRID_SIZE } from '../utils/constants';

interface GameHistoryProps {
  onClose: () => void;
}

const GameHistory: React.FC<GameHistoryProps> = ({ onClose }) => {
  const { history } = useGameStore();
  const [selectedGame, setSelectedGame] = useState<GameRecord | null>(null);

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4 animate-in fade-in duration-200" onClick={onClose}>
      <div className="bg-white rounded-2xl w-full max-w-4xl max-h-[90vh] shadow-2xl flex overflow-hidden relative" onClick={e => e.stopPropagation()}>
        
        {/* Close Button (Desktop) */}
        <button 
            onClick={onClose}
            className="absolute top-4 right-4 p-2 bg-gray-100 hover:bg-gray-200 rounded-full z-10 hidden md:block transition-colors"
        >
            <X size={20} className="text-gray-600" />
        </button>

        {/* Left: History List */}
        <div className={`flex flex-col border-r border-gray-100 bg-gray-50 w-full ${selectedGame ? 'hidden md:flex md:w-1/3' : 'w-full'}`}>
          <div className="p-4 border-b border-gray-200 flex justify-between items-center bg-white">
            <h2 className="text-lg font-bold text-gray-800 flex items-center gap-2">
              <Calendar className="text-blue-600" size={20} />
              游戏记录
            </h2>
            <button onClick={onClose} className="p-1 hover:bg-gray-100 rounded-full md:hidden">
              <X size={20} />
            </button>
          </div>
          
          <div className="overflow-y-auto flex-1 p-2 space-y-2">
            {history.length === 0 ? (
                <div className="text-center py-10 text-gray-400">暂无游戏记录</div>
            ) : (
                history.map((game) => (
                <div 
                    key={game.id}
                    onClick={() => setSelectedGame(game)}
                    className={`p-3 rounded-xl cursor-pointer transition-all border ${
                    selectedGame?.id === game.id 
                        ? 'bg-blue-50 border-blue-200 shadow-sm' 
                        : 'bg-white border-transparent hover:border-gray-200 hover:shadow-sm'
                    }`}
                >
                    <div className="flex justify-between items-start mb-1">
                        <span className={`text-xs px-2 py-0.5 rounded-full ${game.isWin ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                            {game.isWin ? '胜利' : '失败'}
                        </span>
                        <span className="text-xs text-gray-400">
                            {new Date(game.timestamp).toLocaleString()}
                        </span>
                    </div>
                    <div className="flex justify-between items-center mt-2">
                        <div className="text-sm font-medium text-gray-700">
                            {game.mode === 'classic' ? '经典模式' : '自定义模式'}
                        </div>
                        <div className="text-sm font-bold text-gray-900">
                            {game.clicks} 步
                        </div>
                    </div>
                </div>
                ))
            )}
          </div>
        </div>

        {/* Right: Replay View */}
        <div className={`flex-col flex-1 bg-white ${selectedGame ? 'flex' : 'hidden md:flex items-center justify-center'}`}>
          {selectedGame ? (
            <ReplayView game={selectedGame} onBack={() => setSelectedGame(null)} onClose={onClose} />
          ) : (
            <div className="text-gray-400 flex flex-col items-center">
                <History size={48} className="mb-4 opacity-20" />
                <p>选择一局游戏进行复盘</p>
            </div>
          )}
        </div>

      </div>
    </div>
  );
};

// Replay Component
const ReplayView: React.FC<{ game: GameRecord; onBack: () => void; onClose: () => void }> = ({ game, onBack, onClose }) => {
    const [currentStep, setCurrentStep] = useState(0);
    const [isPlaying, setIsPlaying] = useState(false);
    
    // Auto play
    React.useEffect(() => {
        let timer: NodeJS.Timeout;
        if (isPlaying && currentStep < game.moves.length) {
            timer = setTimeout(() => {
                setCurrentStep(prev => prev + 1);
            }, 500);
        } else {
            setIsPlaying(false);
        }
        return () => clearTimeout(timer);
    }, [isPlaying, currentStep, game.moves.length]);

    // Reconstruct board state at current step
    const getBoardState = () => {
        // Initialize empty board
        const board = Array.from({ length: GRID_SIZE }, (_, r) =>
            Array.from({ length: GRID_SIZE }, (_, c) => ({
                row: r, col: c, type: 'empty', revealed: false, marked: false
            }))
        );

        // Apply moves up to current step
        for (let i = 0; i < currentStep; i++) {
            const move = game.moves[i];
            if (move) {
                board[move.row][move.col].revealed = true;
                // We only know the result type from the move record
                // However, in the real game logic, we don't store the full board configuration in history (to save space)
                // Wait, if we don't store the board config (where planes are), we can't show the "unrevealed" planes at the end?
                // Actually, the user requirement is to "review game process".
                // If we want to see the "Head" or "Body" when revealed, we need that info in the move.
                // I added `result` to GameMove interface, so we know what was revealed.
                // But we won't know where the HIDDEN planes were unless we store the initial board configuration.
                // For now, let's just show what was revealed.
                
                // Mapping result string to internal type (though it matches)
                if (move.result === 'head') board[move.row][move.col].type = 'head';
                else if (move.result === 'body') board[move.row][move.col].type = 'body';
                else board[move.row][move.col].type = 'empty';
            }
        }
        return board;
    };

    const boardState = getBoardState();

    return (
        <div className="flex flex-col h-full">
            <div className="p-4 border-b border-gray-100 flex justify-between items-center">
                <button onClick={onBack} className="md:hidden p-2 text-gray-500 hover:bg-gray-100 rounded-lg">
                    ← 返回
                </button>
                <h3 className="font-bold text-gray-800">
                    复盘 ({currentStep}/{game.moves.length} 步)
                </h3>
                <button onClick={onClose} className="p-2 text-gray-500 hover:bg-gray-100 rounded-lg">
                    <X size={20} />
                </button>
            </div>

            <div className="flex-1 overflow-auto p-4 flex items-center justify-center bg-gray-50">
                 <div 
                      className="grid gap-0 border-2 border-gray-800 bg-gray-300 select-none shadow-xl"
                      style={{
                        gridTemplateColumns: `repeat(${GRID_SIZE}, minmax(0, 1fr))`,
                        width: '100%',
                        maxWidth: '400px',
                        aspectRatio: '1/1'
                      }}
                    >
                      {boardState.map((row, r) =>
                        row.map((cell, c) => (
                          <div
                            key={`${r}-${c}`}
                            className={`
                                relative w-full pt-[100%] border border-gray-400
                                ${cell.revealed 
                                    ? cell.type === 'head' ? 'bg-red-500' 
                                    : cell.type === 'body' ? 'bg-blue-500' 
                                    : 'bg-gray-200'
                                : 'bg-white'}
                            `}
                          >
                            {cell.revealed && cell.type === 'marked' && (
                                <div className="absolute inset-0 flex items-center justify-center">🚩</div>
                            )}
                          </div>
                        ))
                      )}
                    </div>
            </div>

            <div className="p-4 border-t border-gray-100 bg-white">
                <div className="flex items-center gap-4 justify-center">
                    <button 
                        onClick={() => setCurrentStep(Math.max(0, currentStep - 1))}
                        disabled={currentStep === 0}
                        className="p-2 rounded-full hover:bg-gray-100 disabled:opacity-30"
                    >
                        Prev
                    </button>
                    <button 
                        onClick={() => setIsPlaying(!isPlaying)}
                        className="flex items-center gap-2 px-6 py-2 bg-blue-600 text-white rounded-full hover:bg-blue-700 transition-colors"
                    >
                        {isPlaying ? 'Pause' : 'Play'} <Play size={16} fill="currentColor" />
                    </button>
                    <button 
                        onClick={() => setCurrentStep(Math.min(game.moves.length, currentStep + 1))}
                        disabled={currentStep === game.moves.length}
                        className="p-2 rounded-full hover:bg-gray-100 disabled:opacity-30"
                    >
                        Next
                    </button>
                </div>
                <div className="mt-4">
                    <input 
                        type="range" 
                        min="0" 
                        max={game.moves.length} 
                        value={currentStep} 
                        onChange={(e) => setCurrentStep(parseInt(e.target.value))}
                        className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer"
                    />
                </div>
            </div>
        </div>
    );
};

function History({ size, className }: { size?: number, className?: string }) {
    return (
        <svg xmlns="http://www.w3.org/2000/svg" width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={className}>
            <path d="M3 12a9 9 0 1 0 9-9 9.75 9.75 0 0 0-6.74 2.74L3 12" />
            <path d="M3 3v9h9" />
            <path d="M12 7v5l4 2" />
        </svg>
    );
}

export default GameHistory;